#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[2001];
        scanf("%s", S);
        int N = strlen(S);
        int dp[N][N];
        int max_len = 0;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                dp[i][j] = 0;
            }
        }
        for (int i = 0; i < N; i++) {
            dp[i][i] = 1;
        }
        for (int len = 2; len <= N; len++) {
            for (int i = 0; i < N - len + 1; i++) {
                int j = i + len - 1;
                if (S[i] <= S[j]) {
                    dp[i][j] = dp[i + 1][j] + 1;
                } else {
                    dp[i][j] = dp[i + 1][j];
                }
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (S[i] >= S[j]) {
                    max_len = (max_len > dp[i][j] + dp[j + 1][N - 1]) ? max_len : dp[i][j] + dp[j + 1][N - 1];
                }
            }
        }
        printf("%d\n", max_len);
    }
    return 0;
}

