code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int N = S.length();
            int[][] dp = new int[N][N];
            int max_len = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    dp[i][j] = 0;
                }
            }
            for (int i = 0; i < N; i++) {
                dp[i][i] = 1;
            }
            for (int len = 2; len <= N; len++) {
                for (int i = 0; i < N - len + 1; i++) {
                    int j = i + len - 1;
                    if (S.charAt(i) <= S.charAt(j)) {
                        dp[i][j] = dp[i + 1][j] + 1;
                    } else {
                        dp[i][j] = dp[i + 1][j];
                    }
                }
            }
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (S.charAt(i) >= S.charAt(j)) {
                        max_len = Math.max(max_len, dp[i][j] + dp[j + 1][N - 1]);
                    }
                }
            }
            System.out.println(max_len);
        }
    }
}

