const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const S = readline().trim();
    const N = S.length;
    const dp = Array(N).fill(0).map(() => Array(N).fill(0));
    let max_len = 0;
    for (let j = 0; j < N; j++) {
        dp[j][j] = 1;
    }
    for (let length = 2; length <= N; length++) {
        for (let j = 0; j < N - length + 1; j++) {
            const k = j + length - 1;
            if (S[j] <= S[k]) {
                dp[j][k] = dp[j + 1][k] + 1;
            } else {
                dp[j][k] = dp[j + 1][k];
            }
        }
    }
    for (let j = 0; j < N; j++) {
        for (let k = 0; k < N; k++) {
            if (S[j] >= S[k]) {
                max_len = Math.max(max_len, dp[j][k] + dp[k + 1][N - 1]);
            }
        }
    }
    console.log(max_len);
}
